import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [statusFilter, setStatusFilter] = useState("ALL");
  const [severityFilter, setSeverityFilter] = useState("ALL");
  const [loading, setLoading] = useState(true);

  // Fetch data
  const fetchData = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:8000/incidents");
      const data = await res.json();
      setIncidents(data);
    } catch {
      alert("Failed to fetch incidents");
    } finally {
      setLoading(false);
    }
  };

  // Auto refresh every 5 sec
  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  // Filtering
  const filtered = incidents.filter(i => {
    return (
      (statusFilter === "ALL" || i.status === statusFilter) &&
      (severityFilter === "ALL" || i.severity === severityFilter)
    );
  });

  // KPIs
  const total = incidents.length;
  const open = incidents.filter(i => i.status === "OPEN").length;
  const closed = incidents.filter(i => i.status === "CLOSED").length;

  return (
    <div style={page}>

      {/* HEADER */}
      <div style={header}>
        <h2 style={{ margin: 0 }}>IT Incident Dashboard</h2>
        <span style={{ color: "#888" }}>Real-time Monitoring</span>
      </div>

      {/* KPI SECTION */}
      <div style={kpiContainer}>
        <KPI label="Total" value={total} color="#2f6fed" />
        <KPI label="Open" value={open} color="#ff4d4f" />
        <KPI label="Closed" value={closed} color="#28a745" />
      </div>

      {/* FILTERS */}
      <div style={filters}>
        <select onChange={(e) => setSeverityFilter(e.target.value)}>
          <option value="ALL">All Priorities</option>
          <option value="P0">P0</option>
          <option value="P1">P1</option>
        </select>

        <select onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="ALL">All Statuses</option>
          <option value="OPEN">Open</option>
          <option value="CLOSED">Closed</option>
        </select>
      </div>

      {/* LOADING */}
      {loading && <p style={{ textAlign: "center" }}>Loading...</p>}

      {/* INCIDENT CARDS */}
      <div style={grid}>
        {filtered.map((i) => (
          <div key={i.id} style={card}>
            
            <div style={cardHeader}>
              <h3 style={{ margin: 0 }}>{i.component_id}</h3>
              <span style={statusBadge(i.status)}>{i.status}</span>
            </div>

            <p style={subText}>Incident #{i.id}</p>

            <div style={badgeRow}>
              <span style={severityBadge(i.severity)}>
                {i.severity}
              </span>

              <span style={signalBadge}>
                Signals: {i.signal_count}
              </span>
            </div>

            <p style={time}>
              {new Date(i.start_time).toLocaleString()}
            </p>

            {/* VIEW DETAILS BUTTON */}
            <Link to={`/incident/${i.id}`}>
              <button style={viewBtn}>
                View Details →
              </button>
            </Link>

          </div>
        ))}
      </div>
    </div>
  );
}

// KPI COMPONENT
function KPI({ label, value, color }) {
  return (
    <div style={{ ...kpi, borderTop: `4px solid ${color}` }}>
      <p style={{ margin: 0, color: "#666" }}>{label}</p>
      <h2 style={{ margin: 0 }}>{value}</h2>
    </div>
  );
}

//
// 🎨 STYLES
//

const page = {
  background: "#f4f6f8",
  minHeight: "100vh",
  padding: "25px",
  fontFamily: "Segoe UI"
};

const header = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  marginBottom: "20px"
};

const kpiContainer = {
  display: "flex",
  gap: "15px",
  marginBottom: "20px"
};

const kpi = {
  background: "#fff",
  padding: "12px",
  borderRadius: "10px",
  width: "120px",
  boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
};

const filters = {
  display: "flex",
  gap: "10px",
  marginBottom: "20px"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
  gap: "20px"
};

const card = {
  background: "#fff",
  padding: "18px",
  borderRadius: "12px",
  boxShadow: "0 3px 10px rgba(0,0,0,0.07)"
};

const cardHeader = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center"
};

const subText = {
  color: "#666",
  fontSize: "14px"
};

const badgeRow = {
  display: "flex",
  justifyContent: "space-between",
  marginTop: "10px"
};

const severityBadge = (sev) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  fontSize: "12px",
  background: sev === "P0" ? "#ffe5e5" : "#fff3cd",
  color: sev === "P0" ? "#d60000" : "#856404"
});

const statusBadge = (status) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  fontSize: "12px",
  background: status === "OPEN" ? "#e6f0ff" : "#e6ffe6",
  color: status === "OPEN" ? "#0056b3" : "#2e7d32"
});

const signalBadge = {
  fontSize: "12px",
  color: "#555"
};

const time = {
  fontSize: "12px",
  color: "#888",
  marginTop: "10px"
};

const viewBtn = {
  marginTop: "12px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  border: "none",
  borderRadius: "6px",
  cursor: "pointer",
  fontSize: "13px"
};
